import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { FinancialRecord } from '../../core/data.models';
import { FinancialsService } from '../../services/financials.service';

@Component({
  selector: 'app-financials-detail',
  templateUrl: './financials-detail.component.html'
})
export class FinancialsDetailComponent implements OnInit {
  item?: FinancialRecord;

  constructor(private route: ActivatedRoute, private router: Router, private svc: FinancialsService) {}

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (!id) return;
    this.svc.list$.subscribe(list => {
      this.item = list.find(i => i.id === id);
      if (!this.item) this.router.navigate(['/financials']);
    });
  }
}
<div *ngIf="item" class="card">
  <h2>{{item.title}}</h2>
  <div class="small">Type: {{item.type}} | Amount: {{item.currency || 'USD'}} {{item.amount}}</div>
  <div style="margin-top:8px">Due Date: {{item.dueDate || '—'}}</div>
  <div style="margin-top:8px">Recurring: {{item.recurring ? 'Yes' : 'No'}}</div>
  <div style="margin-top:8px">Notes: {{item.notes || '—'}}</div>
  <div style="margin-top:12px">
    <a [routerLink]="[item.id, 'edit']">Edit</a>
    <a routerLink="/financials" style="margin-left:8px">Back</a>
  </div>
</div>
